import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import java.io.IOException;

@Controller
public class LogoutController {

    @GetMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        // Invalidate the current session
        // Check if a session exists before invalidating to avoid creating a new one unnecessarily
        if (request.getSession(false) != null) {
            request.getSession().invalidate();
        }

        // Get the 'next' parameter from the request
        String nextUrl = request.getParameter("next");

        // Provide a default redirect URL if 'next' parameter is missing or empty
        if (nextUrl == null || nextUrl.isEmpty()) {
            nextUrl = "/"; // Default to home page or a generic logout success page
        }

        // Redirect to the URL specified in the 'next' parameter
        response.sendRedirect(nextUrl);
    }
}